const keywords = $.input.keywords;
const tone = $.input.tone || 'professional yet conversational';
const wordCount = $.input.wordCount || 1500;
const today = new Date().toISOString().split('T')[0];

let prompt = 'You are a professional SEO content writer. Write a comprehensive blog post based on the following keywords.\n\n';
prompt += 'KEYWORDS: ' + keywords + '\n';
prompt += 'TONE: ' + tone + '\n';
prompt += 'TARGET WORD COUNT: ~' + wordCount + ' words\n';
prompt += 'DATE: ' + today + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Write an SEO-optimized title with the primary keyword\n';
prompt += '- Create a compelling meta description (150-160 chars)\n';
prompt += '- Use proper HTML formatting: <h2>, <h3>, <p>, <ul>/<li>, <strong>, <em>\n';
prompt += '- Include an engaging introduction with a hook\n';
prompt += '- Structure with clear sections and subheadings\n';
prompt += '- Add a conclusion with a call-to-action\n';
prompt += '- Suggest relevant tags and categories\n';
prompt += '- Write a short excerpt\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "title": "SEO-optimized blog title",\n';
prompt += '  "slug": "url-friendly-slug",\n';
prompt += '  "metaDescription": "150-160 char meta description",\n';
prompt += '  "excerpt": "short post excerpt",\n';
prompt += '  "content": "<h2>...</h2><p>...</p> full HTML blog post content",\n';
prompt += '  "tags": ["tag1", "tag2"],\n';
prompt += '  "categories": ["category1"],\n';
prompt += '  "estimatedReadTime": "X min read"\n';
prompt += '}';

return { prompt, today };

let raw = $.steps.aiGenerate.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { title: 'Blog Post', slug: 'blog-post', content: raw, tags: [], categories: [], excerpt: '' }; }
